import{_ as a,o,c as d,a2 as e}from"./chunks/framework.DS_HIvHc.js";const c=JSON.parse('{"title":"질문 잘하는 법","description":"","frontmatter":{},"headers":[],"relativePath":"tips/prompting.md","filePath":"tips/prompting.md","lastUpdated":1773715498000}'),r={name:"tips/prompting.md"};function u(l,t,i,q,h,n){return o(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="질문-잘하는-법" tabindex="-1">질문 잘하는 법 <a class="header-anchor" href="#질문-잘하는-법" aria-label="Permalink to &quot;질문 잘하는 법&quot;">​</a></h1><blockquote><p>같은 부탁이라도 어떻게 말하느냐에 따라 결과 품질이 확 달라집니다.</p></blockquote><h2 id="핵심-원칙-5가지" tabindex="-1">핵심 원칙 5가지 <a class="header-anchor" href="#핵심-원칙-5가지" aria-label="Permalink to &quot;핵심 원칙 5가지&quot;">​</a></h2><h3 id="_1-구체적으로-말하기" tabindex="-1">1. 구체적으로 말하기 <a class="header-anchor" href="#_1-구체적으로-말하기" aria-label="Permalink to &quot;1. 구체적으로 말하기&quot;">​</a></h3><ul><li>❌ &quot;보고서 써줘&quot;</li><li>✅ &quot;3월 마케팅 실적 보고서를 A4 2장 분량으로, 표 포함해서 써줘&quot;</li></ul><h3 id="_2-배경-설명하기" tabindex="-1">2. 배경 설명하기 <a class="header-anchor" href="#_2-배경-설명하기" aria-label="Permalink to &quot;2. 배경 설명하기&quot;">​</a></h3><ul><li>❌ &quot;이메일 써줘&quot;</li><li>✅ &quot;거래처와 첫 미팅 후 감사 인사 이메일 써줘. 상대방은 부장급이고 우리 제품에 관심을 보였어&quot;</li></ul><h3 id="_3-원하는-형태-알려주기" tabindex="-1">3. 원하는 형태 알려주기 <a class="header-anchor" href="#_3-원하는-형태-알려주기" aria-label="Permalink to &quot;3. 원하는 형태 알려주기&quot;">​</a></h3><ul><li>❌ &quot;정리해줘&quot;</li><li>✅ &quot;표로 정리해줘. 열은 이름/담당업무/기한/상태로&quot;</li></ul><h3 id="_4-톤-분량-지정하기" tabindex="-1">4. 톤 &amp; 분량 지정하기 <a class="header-anchor" href="#_4-톤-분량-지정하기" aria-label="Permalink to &quot;4. 톤 &amp; 분량 지정하기&quot;">​</a></h3><ul><li>❌ &quot;공지 써줘&quot;</li><li>✅ &quot;전 직원 대상 공지, 친근하지만 공식적인 톤으로, 10줄 이내로&quot;</li></ul><h3 id="_5-예시-보여주기" tabindex="-1">5. 예시 보여주기 <a class="header-anchor" href="#_5-예시-보여주기" aria-label="Permalink to &quot;5. 예시 보여주기&quot;">​</a></h3><ul><li>❌ &quot;우리 스타일대로 써줘&quot;</li><li>✅ &quot;지난달 보고서처럼 써줘. 파일 이름은 &#39;2월_보고서.docx&#39;야&quot;</li></ul><h2 id="마법의-후속-질문들" tabindex="-1">마법의 후속 질문들 <a class="header-anchor" href="#마법의-후속-질문들" aria-label="Permalink to &quot;마법의 후속 질문들&quot;">​</a></h2><table tabindex="0"><thead><tr><th>결과가 마음에 안 들 때</th><th>더 발전시키고 싶을 때</th></tr></thead><tbody><tr><td>&quot;좀 더 간결하게 줄여줘&quot;</td><td>&quot;여기에 구체적인 수치를 넣어줘&quot;</td></tr><tr><td>&quot;톤을 좀 더 격식 있게 바꿔줘&quot;</td><td>&quot;반대 의견도 고려해서 보완해줘&quot;</td></tr><tr><td>&quot;두 번째 문단이 어색해. 다시 써줘&quot;</td><td>&quot;이걸 프레젠테이션 슬라이드 내용으로 바꿔줘&quot;</td></tr><tr><td>&quot;이건 너무 길어. 핵심만 3줄로&quot;</td><td>&quot;영어 버전도 만들어줘&quot;</td></tr></tbody></table><h2 id="상황별-프롬프트-치트시트" tabindex="-1">상황별 프롬프트 치트시트 <a class="header-anchor" href="#상황별-프롬프트-치트시트" aria-label="Permalink to &quot;상황별 프롬프트 치트시트&quot;">​</a></h2><table tabindex="0"><thead><tr><th>상황</th><th>이렇게 시작하세요</th></tr></thead><tbody><tr><td>이메일</td><td>&quot;[상대/상황]에게 [목적] 이메일 써줘. 톤은 [격식/친근]하게&quot;</td></tr><tr><td>보고서</td><td>&quot;[주제] 보고서를 [분량]으로 써줘. [양식/참고파일] 참고해서&quot;</td></tr><tr><td>데이터 분석</td><td>&quot;[파일명] 파일을 읽고 [알고 싶은 것]을 분석해줘&quot;</td></tr><tr><td>회의록</td><td>&quot;아래 내용을 회의록으로 정리해줘. 액션 아이템 표로&quot;</td></tr><tr><td>번역</td><td>&quot;아래 내용을 [언어]로 번역해줘. [전문용어 처리 방법]&quot;</td></tr><tr><td>기획</td><td>&quot;[주제] 기획서를 써줘. 배경/목표/실행계획/예산 포함&quot;</td></tr><tr><td>비교 분석</td><td>&quot;[A]와 [B]를 비교해줘. [기준] 기준으로 표로 정리&quot;</td></tr></tbody></table>',17)])])}const _=a(r,[["render",u]]);export{c as __pageData,_ as default};
